#nullable enable // autogenerated

using MVZ2.GameContent.Entities;
using MVZ2.Vanilla.Enemies;
using MVZ2.Vanilla.Entities;
using MVZ2Logic.Entities;
using PVZEngine.Definitions;
using PVZEngine.Entities;

namespace MVZ2.GameContent.Enemies
{
    [AutoEntityBehaviourDefinition(VanillaEntityBehaviourNames.enemyState)]
    public class EnemyStateBehaviour : EntityBehaviourDefinition
    {
        public EnemyStateBehaviour(string nsp, string name) : base(nsp, name)
        {
        }

        public override sealed void Update(Entity entity)
        {
            base.Update(entity);
            var passiveState = GetPassiveState(entity);
            if (passiveState >= 0)
            {
                entity.State = passiveState;
                return;
            }
            var over = entity.GetStateOverride();
            if (over >= 0)
            {
                entity.State = passiveState;
                return;
            }
            if (!entity.IsAIFrozen())
            {
                entity.State = GetActiveState(entity);
                return;
            }
        }
        protected virtual int GetPassiveState(Entity enemy)
        {
            if (enemy.IsDead)
            {
                return STATE_DEATH;
            }
            else if (enemy.IsPreviewEnemy())
            {
                return STATE_IDLE;
            }
            return -1;
        }
        protected virtual int GetActiveState(Entity enemy)
        {
            if (EnemyMeleeBehaviour.HasMeleeTarget(enemy))
            {
                return STATE_MELEE_ATTACK;
            }
            else if (enemy.IsCasting())
            {
                return STATE_CAST;
            }
            else
            {
                return STATE_WALK;
            }
        }
        public const int STATE_IDLE = LogicEnemyStates.IDLE;
        public const int STATE_WALK = LogicEnemyStates.WALK;
        public const int STATE_MELEE_ATTACK = LogicEnemyStates.MELEE_ATTACK;
        public const int STATE_CAST = LogicEnemyStates.CAST;
        public const int STATE_DEATH = LogicEnemyStates.DEATH;
        public const int STATE_RANGED_ATTACK = LogicEnemyStates.RANGED_ATTACK;
        public const int STATE_LEAVE = LogicEnemyStates.LEAVE;
    }
}